import React, { useState, useEffect } from 'react';
import {
  CRow, CCol, CCard, CCardBody, CCardHeader, CButton, CSpinner,
  CFormInput, CFormLabel, CFormSelect, CFormCheck,
} from '@coreui/react';
import { getUserPreferences, updateUserPreferences } from '../services/emailService';
import { useApp } from '../context/AppContext';
import toast, { Toaster } from 'react-hot-toast';

export default function SettingsPage() {
  const { userEmail, setUserEmail } = useApp();
  const [emailInput, setEmailInput] = useState(userEmail);
  const [prefs, setPrefs] = useState({ replyTone: 'professional', autoSend: true, customTemplate: '' });
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const fetchPrefs = async () => {
    if (!userEmail) return;
    setLoading(true);
    try {
      const data = await getUserPreferences(userEmail);
      if (data.user) {
        setPrefs({
          replyTone: data.user.replyTone || 'professional',
          autoSend: data.user.autoSend ?? true,
          customTemplate: data.user.customTemplate || '',
        });
      }
    } catch (err) {
      // silently fail if no prefs yet
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchPrefs(); }, [userEmail]);

  const handleSaveEmail = () => {
    if (!emailInput.trim()) return toast.error('Enter a valid email');
    setUserEmail(emailInput.trim());
    toast.success('Email saved!');
  };

  const handleSavePrefs = async () => {
    if (!userEmail) return toast.error('Set your email first');
    setSaving(true);
    try {
      await updateUserPreferences({
        userEmail,
        replyTone: prefs.replyTone,
        autoSend: prefs.autoSend,
        customTemplate: prefs.customTemplate,
      });
      toast.success('Preferences saved!');
    } catch (err) {
      toast.error(err.message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <Toaster position="top-right" />
      <div className="mb-4">
        <h4 className="fw-700 mb-1" style={{ color: '#1a1f36' }}>Settings</h4>
        <p className="text-muted mb-0" style={{ fontSize: '0.88rem' }}>Configure your Outlook email and AI reply preferences</p>
      </div>

      <CRow className="g-4">
        {/* Email Config */}
        <CCol md={6}>
          <CCard>
            <CCardHeader>📧 Outlook Email Address</CCardHeader>
            <CCardBody>
              <p className="text-muted mb-3" style={{ fontSize: '0.84rem' }}>
                Enter your Outlook / Microsoft 365 email address. This is used to fetch emails and calendar events via Microsoft Graph API.
              </p>
              <div className="mb-3">
                <CFormLabel>Email Address</CFormLabel>
                <CFormInput
                  type="email"
                  value={emailInput}
                  onChange={(e) => setEmailInput(e.target.value)}
                  placeholder="you@company.com"
                  onKeyDown={(e) => e.key === 'Enter' && handleSaveEmail()}
                />
              </div>
              {userEmail && (
                <div className="alert alert-success py-2 mb-3" style={{ borderRadius: 8, fontSize: '0.82rem' }}>
                  ✅ Currently using: <strong>{userEmail}</strong>
                </div>
              )}
              <CButton className="btn-ai" onClick={handleSaveEmail}>
                Save Email
              </CButton>
            </CCardBody>
          </CCard>
        </CCol>

        {/* AI Preferences */}
        <CCol md={6}>
          <CCard>
            <CCardHeader>🤖 AI Reply Preferences</CCardHeader>
            <CCardBody>
              {loading ? (
                <div className="text-center py-3"><CSpinner size="sm" /></div>
              ) : (
                <>
                  <div className="mb-3">
                    <CFormLabel>Reply Tone</CFormLabel>
                    <CFormSelect
                      value={prefs.replyTone}
                      onChange={(e) => setPrefs({ ...prefs, replyTone: e.target.value })}
                    >
                      <option value="professional">Professional</option>
                      <option value="friendly">Friendly</option>
                      <option value="casual">Casual</option>
                      <option value="formal">Formal</option>
                    </CFormSelect>
                    <div className="form-text">Sets the tone for Gemini AI-generated replies</div>
                  </div>
                  <div className="mb-3">
                    <CFormCheck
                      id="autoSend"
                      label="Auto-send emails (create draft & send in one step)"
                      checked={prefs.autoSend}
                      onChange={(e) => setPrefs({ ...prefs, autoSend: e.target.checked })}
                    />
                  </div>
                  <div className="mb-3">
                    <CFormLabel>Custom Reply Template (optional)</CFormLabel>
                    <textarea
                      className="form-control"
                      rows={4}
                      value={prefs.customTemplate}
                      onChange={(e) => setPrefs({ ...prefs, customTemplate: e.target.value })}
                      placeholder="Add any custom instructions for AI replies, e.g. 'Always sign off with Best regards, [Name]'"
                      style={{ fontSize: '0.84rem', resize: 'vertical' }}
                    />
                  </div>
                  <CButton className="btn-ai" onClick={handleSavePrefs} disabled={saving || !userEmail}>
                    {saving ? <><CSpinner size="sm" className="me-1" /> Saving…</> : 'Save Preferences'}
                  </CButton>
                </>
              )}
            </CCardBody>
          </CCard>
        </CCol>

        {/* API Info */}
        <CCol md={12}>
          <CCard>
            <CCardHeader>🔌 Backend API Info</CCardHeader>
            <CCardBody>
              <CRow className="g-3">
                {[
                  { label: 'Base URL', value: process.env.REACT_APP_API_URL || 'http://localhost:5000/api/v1' },
                  { label: 'Email Endpoints', value: '/email/emails, /email/generate-reply, /email/create-and-send' },
                  { label: 'Calendar Endpoints', value: '/calendar/events/list, /calendar/events/create' },
                  { label: 'AI Provider', value: 'Google Gemini via backend' },
                ].map((item) => (
                  <CCol key={item.label} md={6}>
                    <div style={{ background: '#f8f9ff', borderRadius: 8, padding: '12px 14px', border: '1px solid #e2e6ff' }}>
                      <div style={{ fontSize: '0.72rem', color: '#6c757d', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 4 }}>
                        {item.label}
                      </div>
                      <div style={{ fontSize: '0.82rem', color: '#1a1f36', fontFamily: 'monospace', wordBreak: 'break-all' }}>
                        {item.value}
                      </div>
                    </div>
                  </CCol>
                ))}
              </CRow>
            </CCardBody>
          </CCard>
        </CCol>
      </CRow>
    </>
  );
}
